   329→
   330→    private RecordBatch validateAndGetRecordBatch() {
   331→        MemoryRecords memoryRecords = recordsBuilder.build();
   332→        Iterator<MutableRecordBatch> recordBatchIter = memoryRecords.batches().iterator();
   333→
   334→        if (!recordBatchIter.hasNext())
   335→            throw new IllegalStateException("Cannot split an empty producer batch.");
   336→
   337→        RecordBatch recordBatch = recordBatchIter.next();
   338→        if (recordBatch.magic() < MAGIC_VALUE_V2 && !recordBatch.isCompressed())
   339→            throw new IllegalArgumentException("Batch splitting cannot be used with non-compressed messages " +
   340→                    "with version v0 and v1");
   341→
   342→        if (recordBatchIter.hasNext())
   343→            throw new IllegalArgumentException("A producer batch should only have one record batch.");
   344→
   345→        return recordBatch;
   346→    }
