   162→                                + maxTimeToBlockMs + " ms. Total memory: " + totalMemory() + " bytes. Available memory: " + availableMemory()
   163→                                + " bytes. Poolable size: " + poolableSize() + " bytes");
   164→                        }
   165→
   166→                        remainingTimeToBlockNs -= timeNs;
   167→
   168→                        // check if we can satisfy this request from the free list,
   169→                        // otherwise allocate memory
   170→                        if (accumulated == 0 && size == this.poolableSize && !this.free.isEmpty()) {
   171→                            // just grab a buffer from the free list
   172→                            buffer = this.free.pollFirst();
   173→                            accumulated = size;
   174→                        } else {
   175→                            // we'll need to allocate memory, but we may only get
   176→                            // part of what we need on this iteration
   177→                            freeUp(size - accumulated);
   178→                            int got = (int) Math.min(size - accumulated, this.nonPooledAvailableMemory);
   179→                            this.nonPooledAvailableMemory -= got;
   180→                            accumulated += got;
   181→                        }
   182→                    }
   183→                    // Don't reclaim memory on throwable since nothing was thrown
   184→                    accumulated = 0;
   185→                } finally {
   186→                    // When this loop was not able to successfully terminate don't loose available memory
   187→                    this.nonPooledAvailableMemory += accumulated;
   188→                    this.waiters.remove(moreMemory);
   189→                }
   190→            }
   191→        } finally {
   192→            // signal any additional waiters if there is more memory left
   193→            // over for them
   194→            try {
   195→                if (!(this.nonPooledAvailableMemory == 0 && this.free.isEmpty()) && !this.waiters.isEmpty())
   196→                    this.waiters.peekFirst().signal();
   197→            } finally {
   198→                // Another finally... otherwise find bugs complains
   199→                lock.unlock();
   200→            }
   201→        }
   202→
   203→        if (buffer == null)
   204→            return safeAllocateByteBuffer(size);
   205→        else
   206→            return buffer;
   207→    }
